import play.api._
import play.api.mvc._
import java.nio.file._
import scala.collection.JavaConverters._
 
class FileController extends Controller {
   def download(filename: String) = Action.async { implicit request =>
     val filePath =  s"uploads/$filename"; // path to the uploaded files, you can use subdirectories for organized storage here as well if needed
     
    java.nio.file.Files.lines(new File(filePath).toPath) match { 
       case Some(lineStream) => lineStream.foreach((s: String) =>  println ( s)) //print the content of file for debugging purpose, remove this when you are ready to serve files  
      }   
     Ok("File Content")       
}